CREATE DATABASE hospital_team_37;
\connect hospital_team_37

DROP SCHEMA IF EXISTS public CASCADE; 
CREATE SCHEMA public;

CREATE TABLE IF NOT EXISTS "DEPARTMENT" (
    "ID" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "Name" TEXT NOT NULL,
    "Building_number" INTEGER NOT NULL,
    "Room_number" INTEGER NOT NULL,
    CONSTRAINT uq_department_location UNIQUE ("Building_number", "Room_number")
);

CREATE TABLE IF NOT EXISTS "DOCTOR" (
    "ID" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "Full_name" TEXT NOT NULL,
    "Specialization" TEXT NOT NULL,
    "Phone" TEXT NOT NULL UNIQUE CHECK ("Phone" ~ '^[+0-9 ()-]{7,20}$'),
    "Email" TEXT NOT NULL UNIQUE CHECK ("Email" ~ '^[^@\s]+@[^@\s]+\.[^@\s]+$'),
    "Hire_date" DATE NOT NULL,
    "Licence_number" INTEGER UNIQUE NOT NULL,
    "Department_ID" INTEGER NOT NULL REFERENCES "DEPARTMENT"("ID")
);

CREATE TABLE IF NOT EXISTS "PATIENT" (
    "ID" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "Full_name" TEXT NOT NULL,
    "National_ID" INTEGER UNIQUE NOT NULL,
    "Date_of_birth" DATE NOT NULL,
    "Gender" TEXT NOT NULL CHECK ("Gender" IN ('male', 'female')),
    "Phone" TEXT NOT NULL UNIQUE CHECK ("Phone" ~ '^[+0-9 ()-]{7,20}$'),
    "Email" TEXT NOT NULL UNIQUE CHECK ("Email" ~ '^[^@\s]+@[^@\s]+\.[^@\s]+$'),
    "Address" TEXT NOT NULL
);

CREATE TABLE IF NOT EXISTS "APPOINTMENT" (
    "ID" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "Date" DATE NOT NULL,
    "Time" TIME NOT NULL,
    "Status" TEXT NOT NULL CHECK ("Status" IN ('scheduled', 'completed', 'cancelled')),
    "Doctor_ID" INTEGER NOT NULL REFERENCES "DOCTOR"("ID"),
    "Patient_ID" INTEGER NOT NULL REFERENCES "PATIENT"("ID")
);

CREATE TABLE IF NOT EXISTS "DIAGNOSIS" (
    "ID" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "Title" TEXT NOT NULL,
    "Description" TEXT NOT NULL,
    "Appointment_ID" INTEGER NOT NULL UNIQUE
        REFERENCES "APPOINTMENT"("ID") ON DELETE CASCADE
);

CREATE TABLE IF NOT EXISTS "PROCEDURE" (
    "ID" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "Name" TEXT NOT NULL,
    "Price" NUMERIC(10, 2) NOT NULL CHECK ("Price" > 0)
);

CREATE TABLE IF NOT EXISTS "APPOINTMENT_PROCEDURE" (
    "Appointment_ID" INTEGER NOT NULL REFERENCES "APPOINTMENT"("ID") ON DELETE CASCADE,
    "Procedure_ID" INTEGER NOT NULL REFERENCES "PROCEDURE"("ID"),
    PRIMARY KEY ("Appointment_ID", "Procedure_ID")
);







